/*
 * PHASE-21 FROZEN FLOOR CONTENT INJECTION INTERFACE
 *
 * The run loop consumes floor content; it never selects content. Fallback packs and
 * the Director both implement FloorContentProvider#getFloor(depth, seed), returning
 * already-authored floor params plus content definitions. The engine validates,
 * generates geometry, places content, and assembles runtime entities through
 * deterministic code only.
 */

import {
  config as defaultConfig,
  type GameConfig
} from "../../config/index.js";
import {
  EnemyDefinitionSchema,
  ItemDefinitionSchema,
  NpcDefinitionSchema,
  QuestDefinitionSchema,
  TrapDefinitionSchema,
  type DepthBand,
  type EnemyDefinition,
  type ItemDefinition,
  type NpcDefinition,
  type QuestDefinition,
  type TrapDefinition
} from "../../schemas/entities/index.js";
import {
  LAYOUT_FLAVORS,
  generateFloor,
  type FloorParams,
  type GeneratedFloor,
  type LayoutFlavor,
  type RoomCountRange
} from "../floorgen/index.js";
import {
  allocateCells,
  collectLegalPlacementCells,
  type PlacementDeviation,
  type PlacementGrid,
  type PlacementHint,
  type PlacementRequest
} from "../floorgen/place.js";
import { costOf, rosterAffordable, rosterCost } from "../enemies/index.js";
import { assembleEnemy } from "../enemies/index.js";
import { createFloorGeometrySlot, type TileGrid } from "../map/index.js";
import { createRng, type Rng } from "../rng/index.js";
import {
  allocateEntityId,
  depthBandForDepth,
  type EntityIdCounters,
  type EntityMap,
  type EntityInstance,
  type GameState,
  type GroundItemEntityInstance,
  type NpcEntityInstance,
  type Position,
  type QuestRuntime,
  type SerializableRecord,
  type TrapEntityInstance
} from "../state/index.js";
import {
  step as turnStep,
  start as turnStart,
  type PlayerAction,
  type TurnEvent,
  type TurnHooks
} from "../turn/index.js";
import { takeOneThingAtHoard, type TakeHoardAction } from "./endings.js";
import { appendRunLog, runEvent, type RunEvent } from "./events.js";

export type HoardFeatureParams = {
  readonly id?: string;
  readonly name?: string;
  readonly hint?: PlacementHint;
};

export type RunFloorParams = FloorParams & {
  readonly hoard?: HoardFeatureParams;
};

export type FloorContent = {
  readonly params: RunFloorParams;
  readonly roster: readonly EnemyDefinition[];
  readonly items: readonly ItemDefinition[];
  readonly traps: readonly TrapDefinition[];
  readonly npcs: readonly NpcDefinition[];
  readonly quest?: QuestDefinition;
};

export interface FloorContentProvider {
  readonly getFloor: (depth: number, seed: string) => FloorContent;
}

export type RunAction = PlayerAction | TakeHoardAction;

export type RunStepOptions = {
  readonly hooks?: TurnHooks;
  readonly config?: GameConfig;
};

export type RunStartOptions = {
  readonly config?: GameConfig;
};

export type RunLoopErrorCode =
  | "provider_threw"
  | "provider_result_malformed"
  | "roster_unaffordable"
  | "floor_generation_failed"
  | "placement_failed"
  | "depth_out_of_range";

export type RunLoopError = {
  readonly kind: "run-loop-error";
  readonly code: RunLoopErrorCode;
  readonly depth: number;
  readonly message: string;
};

export type RunLoopSuccess = {
  readonly ok: true;
  readonly state: GameState;
  readonly events: readonly RunEvent[];
};

export type RunLoopFailure = {
  readonly ok: false;
  readonly state: GameState;
  readonly events: readonly RunEvent[];
  readonly error: RunLoopError;
};

export type RunLoopResult = RunLoopSuccess | RunLoopFailure;

type FloorRuntime = {
  readonly depth: number;
  readonly enteredTurn: number;
  readonly seed: string;
  readonly entrance: Position;
  readonly stairsDown: Position;
  readonly roster: readonly EnemyDefinition[];
  readonly initialSpawnBudgetSpent: number;
  readonly reinforcementSpawnBudgetSpent: number;
  readonly hoard: HoardRuntime | null;
};

type HoardRuntime = {
  readonly id: string;
  readonly name: string;
  readonly position: Position;
};

type FloorRuntimeOpaque = TileGrid & {
  readonly knowledge?: {
    readonly decorativeFeatures?: readonly SerializableRecord[];
    readonly run?: FloorRuntime;
  };
};

type ContentRequest =
  | {
      readonly request: PlacementRequest;
      readonly kind: "enemy";
      readonly definition: EnemyDefinition;
    }
  | {
      readonly request: PlacementRequest;
      readonly kind: "item";
      readonly definition: ItemDefinition;
    }
  | {
      readonly request: PlacementRequest;
      readonly kind: "trap";
      readonly definition: TrapDefinition;
    }
  | {
      readonly request: PlacementRequest;
      readonly kind: "npc";
      readonly definition: NpcDefinition;
    }
  | {
      readonly request: PlacementRequest;
      readonly kind: "hoard";
      readonly params: Required<Pick<HoardFeatureParams, "id" | "name">> &
        Pick<HoardFeatureParams, "hint">;
    };

export const startRun = (
  seed: string,
  provider: FloorContentProvider,
  options: RunStartOptions = {}
): RunLoopResult => {
  const gameConfig = options.config ?? defaultConfig;
  const state = turnStart(seed, { config: gameConfig });

  return enterFloor(state, provider, state.run.depth, gameConfig);
};

export const stepRun = (
  state: GameState,
  action: RunAction,
  provider: FloorContentProvider,
  options: RunStepOptions = {}
): RunLoopResult => {
  const gameConfig = options.config ?? defaultConfig;

  if (action.kind === "take_hoard") {
    const resolved = takeOneThingAtHoard(state);
    if ("illegal" in resolved) {
      return success(state, [
        runEvent(state.run.turn, "run_action_illegal", {
          actionKind: action.kind,
          reason: resolved.reason
        })
      ]);
    }

    const events = [
      runEvent(state.run.turn, "run_action_resolved", {
        actionKind: action.kind
      }),
      ...resolved.events
    ];

    return success(appendRunLog(resolved.state, events), events);
  }

  if (
    action.kind === "descend" &&
    state.run.depth >= gameConfig.runStructure.depthFloors
  ) {
    return success(state, [
      runEvent(state.run.turn, "run_action_illegal", {
        actionKind: action.kind,
        reason: "the final floor ends at the Hoard, not the stairs"
      })
    ]);
  }

  const stepped = turnStep(state, action, { hooks: options.hooks });
  if (
    actionWasIllegal(stepped.events) ||
    stepped.state.run.terminalStatus !== "ACTIVE"
  ) {
    return success(stepped.state, stepped.events);
  }

  if (action.kind === "descend") {
    const nextDepth = state.run.depth + 1;
    const entered = enterFloor(stepped.state, provider, nextDepth, gameConfig);
    if (!entered.ok) {
      return entered;
    }

    return success(entered.state, [...stepped.events, ...entered.events]);
  }

  const softCap = applySoftCap(stepped.state, gameConfig);
  return success(softCap.state, [...stepped.events, ...softCap.events]);

};

const checkUseItemAction = (
  state: GameState,
  action: UseItemAction,
): ActionLegality => {
  if (
    !state.player.inventory.some(
      (slot) => slot?.itemInstanceId === action.itemId,
    )
  ) {
    return illegal(`item ${action.itemId} is not carried`);
  }

  if (action.target === undefined || action.target.kind === "self") {
    return action.direction === undefined ||
      MOVE_DIRECTIONS.some((entry) => entry.direction === action.direction)
      ? LEGAL_ACTION
      : illegal(`unknown use direction ${action.direction}`);
  }

  if (action.target.kind === "entity") {
    return state.entities[action.target.entityId] === undefined
      ? illegal(`target entity ${action.target.entityId} does not exist`)
      : LEGAL_ACTION;
  }

  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  return inBounds(grid, action.target.cell)
    ? LEGAL_ACTION
    : illegal(
        `target cell (${action.target.cell.x}, ${action.target.cell.y}) is outside the map`,
      );
};

const checkPickupAction = (state: GameState): ActionLegality => {
  if (!state.player.inventory.some((slot) => slot === null)) {
    return illegal("inventory is full");
  }

  return sortedEntities(state).some(
    (entity) =>
      entity.kind === "item" &&
      samePosition(entity.position, state.player.position),
  )
    ? LEGAL_ACTION
    : illegal("there is no item here to pick up");
};

const checkTalkAction = (
  state: GameState,
  action: TalkAction,
): ActionLegality => {
  const npc = state.entities[action.npcId];

  if (npc === undefined) {
    return illegal(`npc ${action.npcId} does not exist`);
  }

  if (npc.kind !== "npc") {
    return illegal(`target ${action.npcId} is not an npc`);
  }

  if (!isAdjacentToPlayer(state, npc.position)) {
    return illegal(`npc ${action.npcId} is not adjacent`);
  }

  return LEGAL_ACTION;
};

const checkDescendAction = (state: GameState): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  if (!inBounds(grid, state.player.position)) {
    return illegal(
      `player position (${state.player.position.x}, ${state.player.position.y}) is outside the map`,
    );
  }

  const tile = getTile(grid, state.player.position);

  return tile.terrain === Terrain.StairsDown
    ? LEGAL_ACTION
    : illegal("player is not standing on stairs down");
};

const checkInspectAction = (
  state: GameState,
  action: InspectAction,
): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  return inBounds(grid, action.cell)
    ? LEGAL_ACTION
    : illegal(`inspect cell (${action.cell.x}, ${action.cell.y}) is outside the map`);
};

const availableInspectActions = (state: GameState): readonly InspectAction[] => {
  const grid = gridFromState(state);

  if (grid === null) {
    return [];
  }

  const actions: InspectAction[] = [];

  for (let y = 0; y < grid.height; y += 1) {
    for (let x = 0; x < grid.width; x += 1) {
      actions.push({
        kind: "inspect",
        cell: { x, y },
      });
    }
  }

  return actions;
};

const carriedItems = (inventory: readonly InventorySlot[]) =>
  inventory.filter((slot) => slot !== null);

const pushIfLegal = (
  actions: PlayerAction[],
  state: GameState,
  action: PlayerAction,
): void => {
  if (isActionLegal(checkActionLegality(state, action))) {
    actions.push(action);
  }
};

const sortedEntities = (state: GameState): readonly EntityInstance[] =>
  Object.values(state.entities).sort((a, b) => a.id.localeCompare(b.id));

const isAdjacentToPlayer = (state: GameState, position: Position): boolean =>
  chebyshevDistance(state.player.position, position) <= 1;

const samePosition = (a: Position, b: Position): boolean =>
  a.x === b.x && a.y === b.y;

const offsetForDirection = (direction: MoveDirection): Position => {
  const entry = MOVE_DIRECTIONS.find((candidate) => candidate.direction === direction);

  if (entry === undefined) {
    throw new RangeError(`unknown move direction: ${direction}`);
  }

  return entry.offset;
};

const isTileGridRecord = (
  value: SerializableRecord | null,
): value is SerializableRecord => {
  if (value === null) {
    return false;
  }

  const record = value as {
    readonly kind?: unknown;
    readonly width?: unknown;
    readonly height?: unknown;
    readonly tiles?: unknown;
  };

  return (
    record.kind === "tile-grid" &&
    Number.isSafeInteger(record.width) &&
    Number.isSafeInteger(record.height) &&
    Array.isArray(record.tiles)
  );
};

const illegal = (reason: string): IllegalActionResult => ({
  status: "illegal",
  reason,
});

import { appendFileSync, mkdirSync, writeFileSync } from "node:fs";

import { ENGINE_VERSION, PROTOCOL_VERSION } from "../../schemas/protocol.js";
import type { EngineLogEvent, GameState } from "../../engine/state/index.js";
import { computeStateHash } from "./hash.js";

export type TraceContentRef = {
  readonly providerId: string;
  readonly packVersion: string;
};

export type TraceHeader = {
  readonly recordType: "header";
  readonly protocolVersion: typeof PROTOCOL_VERSION;
  readonly engineVersion: string;
  readonly modelId: string;
  readonly contentRef: TraceContentRef;
  readonly seed: string;
  readonly createdAt: string;
  readonly runId: string;
};

export type TraceTurnLine<
  Action = unknown,
  Event extends EngineLogEvent = EngineLogEvent
> = {
  readonly turn: number;
  readonly action: Action;
  readonly events: readonly Event[];
  readonly stateHash: string;
};

export type EngineLikeStepResult<
  Event extends EngineLogEvent = EngineLogEvent
> = {
  readonly state: GameState;
  readonly events: readonly Event[];
};

export type EngineLikeSession<
  Action,
  Event extends EngineLogEvent = EngineLogEvent
> = {
  readonly state: GameState;
  readonly getAvailableActions?: () => readonly Action[];
  readonly step: (action: Action) => EngineLikeStepResult<Event>;
  readonly isTerminal?: () => boolean;
};

export type RecordedSession<
  Action,
  Event extends EngineLogEvent = EngineLogEvent
> = EngineLikeSession<Action, Event> & {
  readonly trace: TraceRecorder<Action, Event>;
};

export type TraceRecorderOptions = {
  readonly seed: string;
  readonly createdAt: string;
  readonly modelId: string;
  readonly contentRef: TraceContentRef;
  readonly runId?: string;
  readonly writer?: TraceWriter;
};

export type TraceRecorder<
  Action = unknown,
  Event extends EngineLogEvent = EngineLogEvent
> = {
  readonly header: TraceHeader;
  readonly path: string;
  readonly recordTurn: (
    action: Action,
    result: EngineLikeStepResult<Event>
  ) => TraceTurnLine<Action, Event>;
};

export type TraceWriter = {
  readonly path: string;
  readonly writeHeader: (header: TraceHeader) => void;
  readonly appendTurn: <Action, Event extends EngineLogEvent>(
    line: TraceTurnLine<Action, Event>
  ) => void;
};

export type TraceFsAdapter = {
  readonly makeDir: (path: string) => void;
  readonly writeNewFile: (path: string, contents: string) => void;
  readonly appendFile: (path: string, contents: string) => void;
};

export type FileTraceWriterOptions = {
  readonly runId: string;
  readonly rootDir?: string;
  readonly fs?: TraceFsAdapter;
};

export const createTraceRecorder = <
  Action,
  Event extends EngineLogEvent = EngineLogEvent
>(
  options: TraceRecorderOptions
): TraceRecorder<Action, Event> => {
  const runId = options.runId ?? traceRunId(options.seed, options.createdAt);
  const writer = options.writer ?? createFileTraceWriter({ runId });
  const header: TraceHeader = {
    recordType: "header",
    protocolVersion: PROTOCOL_VERSION,
    engineVersion: ENGINE_VERSION,
    modelId: options.modelId,
    contentRef: options.contentRef,
    seed: options.seed,
    createdAt: options.createdAt,
    runId
  };

  writer.writeHeader(header);

  return {
    header,
    path: writer.path,
    recordTurn: (action, result) => {
      // Trace turn numbers use the recorder's post-step state convention.
      const line: TraceTurnLine<Action, Event> = {
        turn: result.state.run.turn,
        action,
        events: result.events,
        stateHash: computeStateHash(result.state)
      };
      writer.appendTurn(line);
      return line;
    }
  };
};

export const record = <Action, Event extends EngineLogEvent = EngineLogEvent>(
  session: EngineLikeSession<Action, Event>,
  options: TraceRecorderOptions
): RecordedSession<Action, Event> => {
  const trace = createTraceRecorder<Action, Event>(options);

  return {
    get state() {
      return session.state;
    },
    getAvailableActions: session.getAvailableActions?.bind(session),
    isTerminal: session.isTerminal?.bind(session),
    step: (action) => {
      const result = session.step(action);
      trace.recordTurn(action, result);
      return result;
    },
    trace
  };
};

export const createFileTraceWriter = (
  options: FileTraceWriterOptions
): TraceWriter => {
  const rootDir = trimTrailingSlash(options.rootDir ?? "runs");
  const dir = `${rootDir}/${options.runId}`;
  const path = `${dir}/trace.ndjson`;
  const fs = options.fs ?? nodeTraceFsAdapter;

  return {
    path,
    writeHeader: (header) => {
      fs.makeDir(dir);
      fs.writeNewFile(path, `${JSON.stringify(header)}\n`);
    },
    appendTurn: (line) => {
      fs.appendFile(path, `${JSON.stringify(line)}\n`);
    }
  };
};

export const traceRunId = (seed: string, createdAt: string): string =>
  `run-${runIdComponent(seed)}-${runIdComponent(createdAt)}`;

const runIdComponent = (value: string): string => {
  const component = value
    .replace(/[^A-Za-z0-9._-]+/g, "-")
    .replace(/^-+|-+$/g, "");

  if (component.length === 0) {
    return "blank";
  }

  return component.slice(0, 80);
};

const trimTrailingSlash = (value: string): string => value.replace(/\/+$/g, "");

const nodeTraceFsAdapter: TraceFsAdapter = {
  makeDir: (path) => {
    mkdirSync(path, { recursive: true });
  },
  writeNewFile: (path, contents) => {
    writeFileSync(path, contents, { encoding: "utf8", flag: "wx" });
  },
  appendFile: (path, contents) => {
    appendFileSync(path, contents, { encoding: "utf8" });
  }
};

import type {
  EntityId,
  EntityInstance,
  GameState,
  InventorySlot,
  Position,
  SerializableRecord,
} from "../state/index.js";
import {
  chebyshevDistance,
  getTile,
  inBounds,
  isWalkableTile,
  Terrain,
  type TileGrid,
} from "../map/index.js";

export const MOVE_DIRECTIONS = [
  { direction: "northwest", offset: { x: -1, y: -1 } },
  { direction: "north", offset: { x: 0, y: -1 } },
  { direction: "northeast", offset: { x: 1, y: -1 } },
  { direction: "west", offset: { x: -1, y: 0 } },
  { direction: "east", offset: { x: 1, y: 0 } },
  { direction: "southwest", offset: { x: -1, y: 1 } },
  { direction: "south", offset: { x: 0, y: 1 } },
  { direction: "southeast", offset: { x: 1, y: 1 } },
] as const;

export type MoveDirection = (typeof MOVE_DIRECTIONS)[number]["direction"];

export type ActionTarget =
  | {
      readonly kind: "self";
    }
  | {
      readonly kind: "entity";
      readonly entityId: EntityId;
    }
  | {
      readonly kind: "cell";
      readonly cell: Position;
    };

export type MoveAction = {
  readonly kind: "move";
  readonly direction: MoveDirection;
};

export type AttackAction = {
  readonly kind: "attack";
  readonly targetId: EntityId;
};

export type UseItemAction = {
  readonly kind: "use_item";
  readonly itemId: string;
  readonly target?: ActionTarget;
  readonly direction?: MoveDirection;
};

export type PickupAction = {
  readonly kind: "pickup";
};

export type TalkAction = {
  readonly kind: "talk";
  readonly npcId: EntityId;
};

export type WaitAction = {
  readonly kind: "wait";
};

export type DescendAction = {
  readonly kind: "descend";
};

export type InspectAction = {
  readonly kind: "inspect";
  readonly cell: Position;
};

export type AbortAction = {
  readonly kind: "abort";
};

export type PlayerAction =
  | MoveAction
  | AttackAction
  | UseItemAction
  | PickupAction
  | TalkAction
  | WaitAction
  | DescendAction
  | InspectAction
  | AbortAction;

export type LegalActionResult = {
  readonly status: "legal";
};

export type IllegalActionResult = {
  readonly status: "illegal";
  readonly reason: string;
};

export type ActionLegality = LegalActionResult | IllegalActionResult;

export const LEGAL_ACTION = { status: "legal" } as const satisfies ActionLegality;

export const isActionLegal = (
  result: ActionLegality,
): result is LegalActionResult => result.status === "legal";

export const checkActionLegality = (
  state: GameState,
  action: PlayerAction,
): ActionLegality => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return illegal(`run is terminal (${state.run.terminalStatus})`);
  }

  switch (action.kind) {
    case "move":
      return checkMoveAction(state, action);
    case "attack":
      return checkAttackAction(state, action);
    case "use_item":
      return checkUseItemAction(state, action);
    case "pickup":
      return checkPickupAction(state);
    case "talk":
      return checkTalkAction(state, action);
    case "wait":
      return LEGAL_ACTION;
    case "descend":
      return checkDescendAction(state);
    case "inspect":
      return checkInspectAction(state, action);
    case "abort":
      return LEGAL_ACTION;
  }
};

export const getAvailableActions = (state: GameState): readonly PlayerAction[] => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return [];
  }

  const actions: PlayerAction[] = [];

  for (const { direction } of MOVE_DIRECTIONS) {
    const action = { kind: "move", direction } as const;
    pushIfLegal(actions, state, action);
  }

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "enemy") {
      pushIfLegal(actions, state, {
        kind: "attack",
        targetId: entity.id,
      });
    }
  }

  for (const item of carriedItems(state.player.inventory)) {
    pushIfLegal(actions, state, {
      kind: "use_item",
      itemId: item.itemInstanceId,
    });
  }

  pushIfLegal(actions, state, { kind: "pickup" });

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "npc") {
      pushIfLegal(actions, state, {
        kind: "talk",
        npcId: entity.id,
      });
    }
  }

  pushIfLegal(actions, state, { kind: "wait" });
  pushIfLegal(actions, state, { kind: "descend" });
  actions.push(...availableInspectActions(state));
  pushIfLegal(actions, state, { kind: "abort" });

  return actions;
};

export const destinationForMove = (
  origin: Position,
  direction: MoveDirection,
): Position => {
  const offset = offsetForDirection(direction);

  return {
    x: origin.x + offset.x,
    y: origin.y + offset.y,
  };
};

export const gridFromState = (state: GameState): TileGrid | null => {
  const opaque = state.floor.geometry.opaque;

  if (!isTileGridRecord(opaque)) {
    return null;
  }

  return opaque as unknown as TileGrid;
};

const checkMoveAction = (
  state: GameState,
  action: MoveAction,
): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  const destination = destinationForMove(state.player.position, action.direction);

  if (!inBounds(grid, destination)) {
    return illegal(
      `move ${action.direction} leaves the map at (${destination.x}, ${destination.y})`,
    );
  }

  const tile = getTile(grid, destination);

  if (!isWalkableTile(tile)) {
    return illegal(`terrain ${tile.terrain} blocks movement`);
  }

  return LEGAL_ACTION;
};

const checkAttackAction = (
  state: GameState,
  action: AttackAction,
): ActionLegality => {
  const target = state.entities[action.targetId];

  if (target === undefined) {
    return illegal(`attack target ${action.targetId} does not exist`);
  }

  if (target.kind !== "enemy") {
    return illegal(`attack target ${action.targetId} is not an enemy`);
  }

  if (!isAdjacentToPlayer(state, target.position)) {
    return illegal(`attack target ${action.targetId} is not adjacent`);
  }

  return LEGAL_ACTION;
};

  return success(softCap.state, [...stepped.events, ...softCap.events]);
};

export const currentFloorRuntime = (state: GameState): FloorRuntime | null =>
  runtimeOpaque(state)?.knowledge?.run ?? null;

const enterFloor = (
  state: GameState,
  provider: FloorContentProvider,
  depth: number,
  gameConfig: GameConfig
): RunLoopResult => {
  if (depth < 1 || depth > gameConfig.runStructure.depthFloors) {
    return failure(state, {
      kind: "run-loop-error",
      code: "depth_out_of_range",
      depth,
      message: `depth ${depth} is outside run depth 1-${gameConfig.runStructure.depthFloors}`
    });
  }

  const band = depthBandForDepth(depth, gameConfig);
  const contentSeed = floorSeed(state.run.seed, depth);
  const contentResult = loadFloorContent(
    provider,
    depth,
    band,
    contentSeed,
    gameConfig
  );

  if (!contentResult.ok) {
    return failure(state, contentResult.error);
  }

  const generated = generateFloor(contentResult.content.params, gameConfig);
  if (!generated.ok) {
    return failure(state, {
      kind: "run-loop-error",
      code: "floor_generation_failed",
      depth,
      message: generated.error.message
    });
  }

  const requests = contentRequests(contentResult.content);
  const allocation = allocateCells(
    placementGrid(generated.floor),
    requests.map(({ request }) => request),
    runRng(state.run.seed).fork(`place:${depth}`)
  );

  if (!allocation.ok) {
    return failure(state, {
      kind: "run-loop-error",
      code: "placement_failed",
      depth,
      message: allocation.error.message
    });
  }

  const assembled = assembleEntities(
    state.ids.entityCounters,
    requests,
    allocation.placements
  );
  const hoard = hoardRuntime(requests, allocation.placements);
  const runtime: FloorRuntime = {
    depth,
    enteredTurn: state.run.turn,
    seed: contentSeed,
    entrance: generated.floor.entrance,
    stairsDown: generated.floor.stairsDown,
    roster: contentResult.content.roster,
    initialSpawnBudgetSpent: rosterCost(contentResult.content.roster),
    reinforcementSpawnBudgetSpent: 0,
    hoard
  };
  const floorId = `floor#${depth}`;
  const nextState = appendRunLog(
    {
      ...state,
      run: {
        ...state.run,
        depth,
        band
      },
      floor: {
        floorId,
        depth,
        band,
        geometry: createRuntimeGeometrySlot(
          `floor-geometry#${depth}`,
          generated.floor.grid,
          runtime
        )
      },
      player: {
        ...state.player,
        position: generated.floor.entrance
      },
      entities: assembled.entities,
      quests: withFloorQuest(state, contentResult.content.quest),
      ids: {
        ...state.ids,
        entityCounters: assembled.counters
      }
    },
    [
      runEvent(state.run.turn, "run_floor_entered", {
        floorId,
        depth,
        band,
        seed: contentSeed,
        rosterCost: runtime.initialSpawnBudgetSpent,
        spawnBudget: gameConfig.enemyDesign.spawnBudgetPoints[band],
        placementDeviationCount: allocation.deviations.length,
        hoardFeatureId: hoard?.id ?? null
      }),
      ...placementDeviationEvents(state.run.turn, allocation.deviations)
    ]
  );

  return success(nextState, nextState.log.slice(state.log.length));
};

const applySoftCap = (
  state: GameState,
  gameConfig: GameConfig
): { readonly state: GameState; readonly events: readonly RunEvent[] } => {
  const runtime = currentFloorRuntime(state);
  if (runtime === null) {
    return { state, events: [] };
  }

  const floorTurn = state.run.turn - runtime.enteredTurn;
  const softCap = gameConfig.runStructure.perFloorSoftCapTurns;
  const interval = gameConfig.runStructure.reinforcementIntervalTurns;

  if (floorTurn <= softCap || (floorTurn - softCap) % interval !== 0) {
    return { state, events: [] };
  }

  const wave = (floorTurn - softCap) / interval;
  const spawnBudget = gameConfig.enemyDesign.spawnBudgetPoints[state.run.band];
  const spent =
    runtime.initialSpawnBudgetSpent + runtime.reinforcementSpawnBudgetSpent;
  const budgetRemaining = Math.max(0, spawnBudget - spent);
  const candidates = runtime.roster.filter(
    (definition) => costOf(definition) <= budgetRemaining
  );

  if (candidates.length === 0) {
    const event = runEvent(state.run.turn, "run_boredom", {
      depth: state.run.depth,
      floorTurn,
      wave,
      budgetRemaining,
      reason: "budget_exhausted"
    });
    return { state: appendRunLog(state, [event]), events: [event] };
  }

  const cells = legalReinforcementCells(state);
  if (cells.length === 0) {
    const event = runEvent(state.run.turn, "run_boredom", {
      depth: state.run.depth,
      floorTurn,
      wave,
      budgetRemaining,
      reason: "no_legal_cell"
    });
    return { state: appendRunLog(state, [event]), events: [event] };
  }

  const rng = runRng(state.run.seed).fork(
    `reinforcement:${state.run.depth}:${wave}`
  );
  const definition = rng.pick(candidates);
  const position = pickStable(cells, rng);
  const allocation = allocateEntityId(state.ids.entityCounters, "enemy");
  const entity = assembleEnemy(definition, {
    id: allocation.id,
    position
  });
  const cost = costOf(definition);
  const nextRuntime: FloorRuntime = {
    ...runtime,
    reinforcementSpawnBudgetSpent: runtime.reinforcementSpawnBudgetSpent + cost
  };
  const nextBudgetRemaining = Math.max(0, budgetRemaining - cost);
  const events = [
    runEvent(state.run.turn, "run_boredom", {
      depth: state.run.depth,
      floorTurn,
      wave,
      budgetRemaining,
      reason: "reinforcement_spawned"
    }),
    runEvent(state.run.turn, "run_reinforcement_spawned", {
      entityId: allocation.id,
      definitionId: definition.id,
      depth: state.run.depth,
      position,
      cost,
      budgetRemaining: nextBudgetRemaining,
      wave
    })
  ];
  const nextState = appendRunLog(
    withRuntime(
      {
        ...state,
        entities: {
          ...state.entities,
          [entity.id]: entity
        },
        ids: {
          ...state.ids,
          entityCounters: allocation.entityCounters
        }
      },
      nextRuntime
    ),
    events
  );

  return { state: nextState, events };
};

const loadFloorContent = (
  provider: FloorContentProvider,
  depth: number,
  band: DepthBand,
  seed: string,
  gameConfig: GameConfig
):
  | { readonly ok: true; readonly content: FloorContent }
  | { readonly ok: false; readonly error: RunLoopError } => {
  let raw: unknown;

  try {
    raw = provider.getFloor(depth, seed);
  } catch (error) {
    return {
      ok: false,
      error: {
        kind: "run-loop-error",
        code: "provider_threw",
        depth,
        message:
          error instanceof Error
            ? error.message
            : "floor content provider threw a non-error value"
      }
    };
  }

  const record = asRecord(raw);
  if (record === null) {
    return malformed(depth, "provider result must be an object");
  }

  const params = parseRunFloorParams(record.params, depth, gameConfig);
  if (!params.ok) {
    return malformed(depth, params.message);
  }

  const roster = EnemyDefinitionSchema.array().safeParse(record.roster);
  if (!roster.success) {
    return malformed(depth, `roster is malformed: ${roster.error.message}`);
  }

  if (!rosterAffordable(roster.data, band)) {
    return {
      ok: false,
      error: {
        kind: "run-loop-error",
        code: "roster_unaffordable",
        depth,
        message: `roster is outside ${band} spawn budget`
      }
    };
  }

  const items = ItemDefinitionSchema.array().safeParse(record.items);
  if (!items.success) {
