import { idx, type Tile } from "../map/index.js";
import type {
  EntityId,
  EntityInstance,
  GameState,
  Position,
} from "../state/index.js";
import {
  defaultVisibleFog,
  fogFromState,
  floorKnowledge,
  gridFromState,
  isTrapRevealed,
} from "./floor-runtime.js";
import {
  enemyGlyph,
  GLYPH_NPC,
  GLYPH_PLAYER,
  GLYPH_TRAP,
  itemGlyph,
  rememberedTerrainGlyph,
  terrainGlyph,
} from "./glyphs.js";

export const renderHudLine = (state: GameState): string => {
  const statuses = state.player.statuses
    .map((application) => application.status)
    .join(",");
  const statusSuffix = statuses.length > 0 ? ` ${statuses}` : "";

  return [
    `d${state.run.depth}`,
    `t${state.run.turn}`,
    `HP ${state.player.hp.current}/${state.player.hp.max}`,
    `full ${state.player.fullness.current}/${state.player.fullness.max}`,
    `L${state.player.level}`,
    `xp ${state.player.xp}${statusSuffix}`,
  ].join(" ");
};

export const render = (state: GameState): string => {
  const grid = gridFromState(state);

  if (grid === null) {
    return renderHudLine(state);
  }

  const fog = fogFromState(state, grid) ?? defaultVisibleFog(grid);
  const knowledge = floorKnowledge(state);
  const mapRevealed = knowledge.mapRevealed === true;
  const lines: string[] = [];

  for (let y = 0; y < grid.height; y += 1) {
    let row = "";

    for (let x = 0; x < grid.width; x += 1) {
      const position = { x, y };
      const index = idx(grid, position);
      const memory = fog.tiles[index];

      if (memory === undefined) {
        row += " ";
        continue;
      }

      if (!mapRevealed && memory.state === "unseen") {
        row += " ";
        continue;
      }

      if (!mapRevealed && memory.state === "remembered") {
        const tile = memory.rememberedTile;

        row += tile === null ? " " : rememberedTerrainGlyph(tile);
        continue;
      }

      const tile = grid.tiles[index];

      row +=
        tile === undefined ? " " : glyphAt(state, position, tile);
    }

    lines.push(row);
  }

  lines.push(renderHudLine(state));

  return lines.join("\n");
};

const glyphAt = (state: GameState, position: Position, tile: Tile): string => {
  if (
    state.player.position.x === position.x &&
    state.player.position.y === position.y
  ) {
    return GLYPH_PLAYER;
  }

  const entities = entitiesAt(state, position);

  const enemy = entities.find((entity) => entity.kind === "enemy");

  if (enemy !== undefined) {
    return enemyGlyph(enemy.definition.glyph);
  }

  const npc = entities.find((entity) => entity.kind === "npc");

  if (npc !== undefined) {
    return GLYPH_NPC;
  }

  const item = entities.find((entity) => entity.kind === "item");

  if (item !== undefined) {
    return itemGlyph(item.definition, item.identified);
  }

  const trap = entities.find((entity) => entity.kind === "trap");

  if (
    trap !== undefined &&
    isTrapRevealed(state, trap.id, trap.behaviorRuntime)
  ) {
    return GLYPH_TRAP;
  }

  return terrainGlyph(tile);
};

const entitiesAt = (
  state: GameState,
  position: Position,
): readonly EntityInstance[] =>
  Object.values(state.entities)
    .filter(
      (entity) =>
        entity.position.x === position.x && entity.position.y === position.y,
    )
    .sort((left, right) => compareEntityIds(left.id, right.id));

const compareEntityIds = (left: EntityId, right: EntityId): number => {
  const parsedLeft = parseEntityId(left);
  const parsedRight = parseEntityId(right);
  const kindOrder = parsedLeft.kind.localeCompare(parsedRight.kind);

  return kindOrder === 0
    ? parsedLeft.index - parsedRight.index
    : kindOrder;
};

const parseEntityId = (
  id: EntityId,
): { readonly kind: string; readonly index: number } => {
  const [kind, rawIndex] = id.split("#");

  return {
    kind: kind ?? "",
    index: Number.parseInt(rawIndex ?? "0", 10),
  };
};

import type { FogMemory, TileGrid } from "../map/index.js";
import type { EntityId, GameState } from "../state/index.js";

export type FloorKnowledge = {
  readonly mapRevealed?: boolean;
  readonly revealedItemIds?: readonly EntityId[];
  readonly revealedEnemyIds?: readonly EntityId[];
  readonly revealedTrapIds?: readonly EntityId[];
};

type FloorRuntimeOpaque = TileGrid & {
  readonly fog?: FogMemory;
  readonly knowledge?: FloorKnowledge;
};

export const gridFromState = (state: GameState): TileGrid | null => {
  const opaque = state.floor.geometry.opaque;

  if (
    opaque === null ||
    typeof opaque !== "object" ||
    !("kind" in opaque) ||
    opaque.kind !== "tile-grid" ||
    typeof opaque.width !== "number" ||
    typeof opaque.height !== "number" ||
    !Array.isArray(opaque.tiles)
  ) {
    return null;
  }

  return opaque as unknown as TileGrid;
};

export const fogFromState = (
  state: GameState,
  grid: TileGrid,
): FogMemory | null => {
  const fog = (state.floor.geometry.opaque as FloorRuntimeOpaque | null)?.fog;

  if (
    fog !== undefined &&
    fog.width === grid.width &&
    fog.height === grid.height &&
    fog.tiles.length === grid.tiles.length
  ) {
    return fog;
  }

  return null;
};

export const defaultVisibleFog = (grid: TileGrid): FogMemory => ({
  ownerId: "player",
  width: grid.width,
  height: grid.height,
  tiles: grid.tiles.map((tile) => ({
    state: "visible" as const,
    rememberedTile: tile,
  })),
});

export const floorKnowledge = (state: GameState): FloorKnowledge =>
  (state.floor.geometry.opaque as FloorRuntimeOpaque | null)?.knowledge ?? {};

export const isTrapRevealed = (
  state: GameState,
  trapId: EntityId,
  behaviorRuntime: { readonly [key: string]: unknown },
): boolean => {
  if (behaviorRuntime.revealed === true) {
    return true;
  }

  const knowledge = floorKnowledge(state);

  return knowledge.revealedTrapIds?.includes(trapId) ?? false;
};

import type { Position } from "../state/index.js";
import { getTile, idx, neighbors8, type TileGrid } from "./grid.js";
import { isWalkableTile, Terrain, type Tile } from "./terrain.js";

export type PathOptions = {
  readonly openDoors?: boolean;
  readonly isOccupied?: (position: Position) => boolean;
};

const CARDINAL_STEP_COST = 10;
const DIAGONAL_STEP_COST = 14;

// Neighbor expansion uses neighbors8 order: NW, N, NE, W, E, SW, S, SE (row-major
// offsets from grid.ts). Open-set ties break on f, then h, then y, then x.
const compareOpenNodes = (
  a: { f: number; h: number; position: Position },
  b: { f: number; h: number; position: Position },
): number => {
  if (a.f !== b.f) {
    return a.f - b.f;
  }

  if (a.h !== b.h) {
    return a.h - b.h;
  }

  if (a.position.y !== b.position.y) {
    return a.position.y - b.position.y;
  }

  return a.position.x - b.position.x;
};

const positionsEqual = (a: Position, b: Position): boolean =>
  a.x === b.x && a.y === b.y;

const stepCost = (from: Position, to: Position): number => {
  const dx = Math.abs(to.x - from.x);
  const dy = Math.abs(to.y - from.y);

  return dx !== 0 && dy !== 0 ? DIAGONAL_STEP_COST : CARDINAL_STEP_COST;
};

const octileHeuristic = (from: Position, to: Position): number => {
  const dx = Math.abs(to.x - from.x);
  const dy = Math.abs(to.y - from.y);
  const min = Math.min(dx, dy);
  const max = Math.max(dx, dy);

  return min * DIAGONAL_STEP_COST + (max - min) * CARDINAL_STEP_COST;
};

const isPassableTile = (tile: Tile, openDoors: boolean): boolean => {
  if (!isWalkableTile(tile)) {
    return false;
  }

  if (tile.terrain === Terrain.Door && tile.door === "closed" && !openDoors) {
    return false;
  }

  return true;
};

const isPassable = (
  grid: TileGrid,
  position: Position,
  options: PathOptions,
  exempt: Position,
): boolean => {
  if (!positionsEqual(position, exempt) && options.isOccupied?.(position)) {
    return false;
  }

  return isPassableTile(getTile(grid, position), options.openDoors ?? false);
};

export const path = (
  grid: TileGrid,
  from: Position,
  to: Position,
  options: PathOptions = {},
): readonly Position[] | null => {
  if (positionsEqual(from, to)) {
    return isPassable(grid, from, options, from) ? [from] : null;
  }

  if (
    !isPassable(grid, from, options, from) ||
    !isPassable(grid, to, options, from)
  ) {
    return null;
  }

  const goalIndex = idx(grid, to);
  const startIndex = idx(grid, from);

  const gScore = new Map<number, number>([[startIndex, 0]]);
  const cameFrom = new Map<number, number>();
  const closed = new Set<number>();

  type OpenNode = {
    index: number;
    position: Position;
    f: number;
    h: number;
  };

  const open: OpenNode[] = [
    {
      index: startIndex,
      position: from,
      f: octileHeuristic(from, to),
      h: octileHeuristic(from, to),
    },
  ];

  while (open.length > 0) {
    open.sort(compareOpenNodes);
    const current = open.shift();

    if (current === undefined) {
      break;
    }

    if (closed.has(current.index)) {
      continue;
    }

    if (current.index === goalIndex) {
      const route: Position[] = [to];
      let cursor = goalIndex;

      while (cursor !== startIndex) {
        const previous = cameFrom.get(cursor);

        if (previous === undefined) {
          return null;
        }

        cursor = previous;
        route.push({
          x: cursor % grid.width,
          y: Math.floor(cursor / grid.width),
        });
      }

      route.reverse();
      return route;
    }

    closed.add(current.index);

    const currentG = gScore.get(current.index) ?? Number.POSITIVE_INFINITY;

    for (const neighbor of neighbors8(grid, current.position)) {
      const neighborIndex = idx(grid, neighbor);

      if (closed.has(neighborIndex)) {
        continue;
      }

      if (!isPassable(grid, neighbor, options, from)) {
        continue;
      }

      const tentativeG = currentG + stepCost(current.position, neighbor);
      const knownG = gScore.get(neighborIndex);

      if (knownG !== undefined && tentativeG >= knownG) {
        continue;
      }

      cameFrom.set(neighborIndex, current.index);
      gScore.set(neighborIndex, tentativeG);

      const h = octileHeuristic(neighbor, to);
      open.push({
        index: neighborIndex,
        position: neighbor,
        f: tentativeG + h,
        h,
      });
    }
  }

  return null;
};

