  const trap = state.entities[trapId];
  if (trap?.kind !== "trap") {
    return state;
  }

  return {
    ...state,
    entities: {
      ...state.entities,
      [trapId]: {
        ...trap,
        armed: false,
      },
    },
  };
};

const withFloorMetadata = (
  state: GameState,
  metadata: {
    readonly knowledge?: FloorKnowledge;
  },
): GameState => {
  const grid = gridFromState(state);
  if (grid === null) {
    return state;
  }

  const opaque = state.floor.geometry.opaque;
  const existing =
    opaque !== null && typeof opaque === "object"
