export const behaviorConditionFires = (
  state: GameState,
  enemy: EnemyEntityInstance,
  behavior: Behavior,
): boolean => {
  switch (behavior.kind) {
    case "flee_low_hp": {
      const threshold = behavior.fleeLowHp?.thresholdPercent;

      if (threshold === undefined) {
        return false;
      }

      return (
        enemy.currentHP * 100 <=
        threshold * enemy.definition.stats.hp
      );
    }
    case "approach_melee":
    case "keep_range":
    case "territorial":
    case "guard":
    case "patrol":
      return true;
    default:
      return false;
  }
};

const evaluateApproachMelee = (
  state: GameState,
  enemyId: EntityId,
): BehaviorAction => {
  const enemy = state.entities[enemyId];

  if (enemy?.kind !== "enemy") {
    return { kind: "wait" };
  }

  if (isAdjacent(enemy.position, state.player.position)) {
    return { kind: "attack", targetId: "player" };
  }

  const approachGoal = approachGoalFor(state, enemyId);

  if (approachGoal === null) {
    return { kind: "wait" };
  }

  const prepared = prepareSpecialRuntimeForActorTurn(state, actor.id, action);
  const rngContext = createAiRngContext(prepared.state);
  const decided = evaluateBehaviors(prepared.state, actor.id, rngContext);
  const result = normalizeHookResult(
    executeBehaviorAction(prepared.state, actor.id, decided, rngContext),
  );

  return {
    state: withAiRngCursor(result.state, rngContext),
    events: [...prepared.events, ...result.events],
  };
};

