const tickNaturalRegen: TickHook = ({ state }) => {
  const completedTurn = state.run.turn + 1;
  const regen = config.playerCharacter.naturalRegen;

  if (completedTurn % regen.everyTurns !== 0) {
    return state;
  }

  if (state.player.fullness.current <= regen.requiresFullnessAbove) {
    return state;
  }

  if (state.player.hp.current >= state.player.hp.max) {
    return state;
  }

  const hpBefore = state.player.hp.current;
  const hpAfter = Math.min(state.player.hp.max, hpBefore + regen.hpGain);

  if (hpAfter === hpBefore) {
    return state;
  }

  return {
    state: withPlayerHp(state, hpAfter, state.player.hp.max),
    events: []
  };
};

export const playerTickHooks = {
  hunger: tickHunger,
  regen: tickNaturalRegen
} as const satisfies Pick<TickHooks, PlayerTickHookName>;

export const unregisterPlayerTickHooks = (() => {
  const unregisterHunger = registerTickHook("hunger", tickHunger);
  const unregisterRegen = registerTickHook("regen", tickNaturalRegen);

  return () => {
    unregisterRegen();
    unregisterHunger();
  };
})();

const applyPendingLevelUps = (state: GameState): ApplyXpResult => {
  const events: TurnEvent[] = [];
  let nextState = state;

  while (
    nextState.player.level < bounds.playerCharacter.levelCap &&
    nextState.player.xp >= xpToNextLevel(nextState.player.level)
  ) {
    const levelBefore = nextState.player.level;
    const xpBefore = nextState.player.xp;
    const maxHpBefore = nextState.player.hp.max;
    const currentHpBefore = nextState.player.hp.current;
    const threshold = xpToNextLevel(levelBefore);
    const levelAfter = levelBefore + 1;
    const xpAfter = xpBefore - threshold;
    const maxHpAfter = derivePlayerBaseStats(levelAfter).maxHp;
    const hpDelta = maxHpAfter - maxHpBefore;
    const currentHpAfter = Math.min(
      maxHpAfter,
      currentHpBefore + Math.max(0, hpDelta)
    );

    nextState = {
      ...nextState,
      player: {
        ...nextState.player,
        level: levelAfter,
        xp: xpAfter,
        hp: {
          current: currentHpAfter,
          max: maxHpAfter
        }
      }
    };

    events.push(
      playerEvent(state, "level_up", {
        actorId: "player",
        levelBefore,
        levelAfter,
        xpBefore,
        xpAfter,
        xpToNextLevel:
          levelAfter < bounds.playerCharacter.levelCap
            ? xpToNextLevel(levelAfter)
            : null,
        maxHpBefore,
        maxHpAfter,

  southeast: { x: 1, y: 1 },
} as const satisfies Record<MoveDirection, Position>;

export const resolveUseItemAction: ActionResolver<UseItemAction> = (
  state,
  action,
): ActionResolverResult => {
  const item = state.player.inventory.find(
    (slot) => slot?.itemInstanceId === action.itemId,
  );

  if (item === null || item === undefined) {
    return {
      illegal: true,
      reason: `item ${action.itemId} is not carried`,
    };
  }

  switch (item.definition.kind) {
    case "weapon":
    case "armor":
    case "charm":
      return useEquipmentItem(state, item);
    case "draught":
      return useBundledItem(state, {
        item,
        bundle: item.definition.draught?.effect ?? null,
        trigger: "quaff",
        action,
        consume: true,
      });
    case "note":
      return useBundledItem(state, {
        item,
        bundle: item.definition.note?.effect ?? null,
        trigger: "read",
        action,
        consume: true,
      });
    case "throwable":
      return useBundledItem(state, {
        item,
        bundle: item.definition.throwable?.effect ?? null,
        trigger: "throw_hit",
        action,
        consume: true,
      });
    case "food":
      return useBundledItem(state, {
        item,
        bundle: item.definition.food?.effect ?? null,
        trigger: "use",
        action,
        consume: true,
      });
    case "tool":
      return useToolItem(state, item, action);
    case "key_item":
    case "coin":
      return {
        illegal: true,
        reason: `${item.definition.kind} items cannot be used directly`,
      };
  }
};

export const resolveItemAwareAttackAction: ActionResolver<AttackAction> = (
  state,
  action,
): ActionResolverResult => {
  const combat = resolveAttack(state, "player", action.targetId);

  if ("illegal" in combat) {
    return combat;
  }

  return dispatchCombatItemProcs({
    stateBefore: state,
    state: combat.state,
    events: combat.events,
  });
};

