  if ("illegal" in equipped) {
    return equipped;
  }

  let nextState = equipped.state;
  const events = [...equipped.events];

  if (item.definition.kind === "weapon" || item.definition.kind === "armor") {
    nextState = revealEquipmentBonus(nextState, item.itemInstanceId);
  }

  if (item.definition.kind === "charm") {
    nextState = identifyDefinitionByUse(nextState, item.definition);
    const passive = item.definition.charm?.passive;

    if (passive !== undefined && passive !== null) {
      events.push(
        itemTriggeredEvent(state, {
          itemInstanceId: item.itemInstanceId,
          definitionId: item.definition.id,
          trigger: "equip_passive",
          targetIds: ["player"],
          cells: [state.player.position],
          whiffed: false,
        }),
      );
    }
  }

  return {
    state: nextState,
    events: maybeIdentifiedEvent(state, item, nextState, events),
  };
};

const useBundledItem = (
  state: GameState,
  options: Omit<TriggerDispatchOptions, "bundle"> & {
    readonly bundle: EffectBundle | null;
    readonly consume: boolean;
  },
): ActionResolverResult => {
  const { item, bundle, trigger, action } = options;

  if (bundle === null) {
    return {
      illegal: true,
      reason: `${item.definition.kind} item ${item.itemInstanceId} has no effect bundle`,
    };
  }

  if (bundle.trigger.kind !== trigger) {
    return {
      illegal: true,
      reason: `${item.definition.kind} item ${item.itemInstanceId} does not declare a ${trigger} trigger`,
    };
  }

  const dispatched = dispatchItemTrigger(state, {
    item,
    bundle,
    trigger,
    action,
  });
  let nextState = identifyDefinitionByUse(dispatched.state, item.definition);
  let events = maybeIdentifiedEvent(state, item, nextState, dispatched.events);

  if (options.consume) {
    const consumed = consumeOne(nextState, item);
    nextState = consumed.state;
    events = [...events, ...consumed.events];
  }

  return {
    state: nextState,
    events,
  };
};

const useToolItem = (
  state: GameState,
  item: PlayerItemStack,
  action: UseItemAction,
): ActionResolverResult => {
  const bundle = item.definition.tool?.effect ?? null;

  if (bundle === null) {
    return {
      illegal: true,
      reason: `tool item ${item.itemInstanceId} has no effect bundle`,
    };
  }

  if (bundle.trigger.kind !== "use" || bundle.trigger.use === null) {
    return {
      illegal: true,
      reason: `tool item ${item.itemInstanceId} does not declare a use trigger`,
    };
  }

  const chargesBefore =
    state.run.itemKnowledge.chargesByItemInstanceId[item.itemInstanceId] ??
    bundle.trigger.use.charges;

  if (chargesBefore < 1) {
    return {
      illegal: true,
      reason: `tool item ${item.itemInstanceId} has no charges`,
    };
  }

  const dispatched = dispatchItemTrigger(state, {
    item,
    bundle,
    trigger: "use",
    action,
  });
  const chargesAfter = chargesBefore - 1;
  let nextState = withToolCharges(
    identifyDefinitionByUse(dispatched.state, item.definition),
    item.itemInstanceId,
    chargesAfter,
  );
  let events = maybeIdentifiedEvent(state, item, nextState, [
    ...dispatched.events,
    itemChargeUsedEvent(state, item, chargesBefore, chargesAfter),
  ]);

  if (chargesAfter === 0) {
    const consumed = consumeOne(nextState, item);
    nextState = consumed.state;
    events = [
      ...events,
      ...consumed.events,
      itemDepletedEvent(state, item),
    ];
  }

  return {
    state: nextState,
    events,
  };
};

const dispatchItemTrigger = (
  state: GameState,
  options: TriggerDispatchOptions,
): {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
} => {
  if (options.trigger === "quaff") {
    return dispatchBundleToTargeting(state, {
      itemInstanceId: options.item.itemInstanceId,
      definitionId: options.item.definition.id,
      trigger: options.trigger,
      bundle: options.bundle,
      sourceId: "player",
      origin: state.player.position,
      targetCell: state.player.position,
    });
  }

  if (options.trigger === "throw_hit") {
    return dispatchThrowHit(state, options);
  }

  const targetCell = targetCellForAction(state, options.action, options.bundle.targeting);

  return dispatchBundleToTargeting(state, {
    itemInstanceId: options.item.itemInstanceId,
    definitionId: options.item.definition.id,
    trigger: options.trigger,
    bundle: options.bundle,
    sourceId: "player",
    origin: state.player.position,
    targetCell,
  });
};

const dispatchThrowHit = (
  state: GameState,
  options: TriggerDispatchOptions,
): {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
} => {
  const grid = gridFromState(state);

  if (grid === null) {
    return {
      state,
      events: [],
    };
  }

  const range = rangeForThrow(options.bundle.targeting);
  const targetCell = targetCellForAction(state, options.action, options.bundle.targeting);
  const aimedCell =
    targetCell ?? cellInDirection(state.player.position, options.action.direction, range);

  if (aimedCell === null) {
    return {
      state,
      events: [
        itemTriggeredEvent(state, {
          itemInstanceId: options.item.itemInstanceId,
          definitionId: options.item.definition.id,
          trigger: "throw_hit",
          targetIds: [],
          cells: [],
          whiffed: true,
        }),
      ],
    };
  }

  const impact = throwImpact(state, grid, state.player.position, aimedCell, range);
  if (impact.impactCell === null) {
    return {
      state,
      events: [
        itemTriggeredEvent(state, {
          itemInstanceId: options.item.itemInstanceId,
          definitionId: options.item.definition.id,
          trigger: "throw_hit",
          targetIds: [],
          cells: impact.cells,
          whiffed: true,
        }),
      ],
    };
  }

  const dispatched = dispatchBundleToTargeting(state, {
    itemInstanceId: options.item.itemInstanceId,
    definitionId: options.item.definition.id,
    trigger: "throw_hit",
    bundle: options.bundle,
    sourceId: "player",
    origin: state.player.position,
    targetCell: impact.impactCell,
  });

  return {
    state: dispatched.state,
    events: dispatched.events,
  };
};

const dispatchBundleToTargeting = (
  state: GameState,
  options: BundleDispatchOptions,
): {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
} => {
  const geometry = resolveTargetingGeometry(
    state,
    options.origin,
    options.bundle.targeting,
    {
      originActorId: options.sourceId,
      targetCell: options.targetCell,

  attackerAttack: number,
  defenderDefense: number,
  varianceMultiplier: number,
): number =>
  Math.max(
    config.combatMath.minimumDamage,
    Math.round(
      calculateBaseDamage(attackerAttack, defenderDefense) *
        varianceMultiplier,
    ),
  );

export const resolveAttack = (
  state: GameState,
  attackerId: CombatActorId,
  defenderId: CombatActorId,
): ActionResolverResult => {
  const attacker = combatActor(state, attackerId);

  if (attacker === null) {
    return {
      illegal: true,
      reason: `attacker ${attackerId} is not a combat actor`,
    };
  }

  const interceptedDefenderId = applyAttackInterceptors(
    state,
    attackerId,
    defenderId,
  );
  const defender = combatActor(state, interceptedDefenderId);

  if (defender === null) {
    return {
      illegal: true,
      reason: `defender ${interceptedDefenderId} is not a combat actor`,
    };
  }

  if (!isAdjacent(attacker.position, defender.position)) {
    return {
      illegal: true,
      reason: `defender ${interceptedDefenderId} is not adjacent to attacker ${attackerId}`,
    };
  }

  return resolveAttackRoll(state, attacker, defender);
};

export type BoltAttackOptions = {
  readonly range?: number;
};

export const resolveBoltAttack = (
  state: GameState,
  attackerId: CombatActorId,
  targetCell: Position,
  options: BoltAttackOptions = {},
): ActionResolverResult => {
  const attacker = combatActor(state, attackerId);

  if (attacker === null) {
    return {
      illegal: true,
      reason: `attacker ${attackerId} is not a combat actor`,
    };
  }

  const grid = gridFromState(state);
  if (grid === null) {
    return {
      illegal: true,
      reason: "floor geometry is not loaded",
    };
  }

  if (!inBounds(grid, targetCell)) {
    return {
      illegal: true,
      reason: `bolt target cell (${targetCell.x}, ${targetCell.y}) is outside the map`,
    };
  }

  const range =
    options.range ?? bounds.effectVocabulary.targetingShapes.boltRangeTiles.max;
  const rangeBounds = bounds.effectVocabulary.targetingShapes.boltRangeTiles;

  if (
    !Number.isSafeInteger(range) ||
    range < rangeBounds.min ||
    range > rangeBounds.max
  ) {
    return {
      illegal: true,
      reason: `bolt range must be ${rangeBounds.min}-${rangeBounds.max}`,
    };
  }

  const target = findBoltTarget(state, grid, attacker, targetCell, range);

  if (target.status === "miss") {
    return {
      state,
      events: [
        combatEvent(state, "attack_missed", {
          actorId: attacker.id,
          defenderId: null,
          attackerAttack: null,
          defenderDefense: null,
          hitRoll: null,
          hitChancePercent: config.combatMath.hitChancePercent,
          reason: target.reason,
        }),
      ],
    };
  }

  const interceptedDefenderId = applyAttackInterceptors(
    state,
    attackerId,
    target.actor.id,
  );
  const defender = combatActor(state, interceptedDefenderId);

  if (defender === null) {
    return {
      illegal: true,
      reason: `defender ${interceptedDefenderId} is not a combat actor`,
    };
  }

  return resolveAttackRoll(state, attacker, defender);
};

export const resolveAttackAction: ActionResolver<AttackAction> = (
  state,
  action,
): ActionResolverResult => resolveAttack(state, "player", action.targetId);

export const registerCombatActionResolver = (): (() => void) =>
  registerActionResolver("attack", resolveAttackAction);

export const unregisterCombatActionResolver = registerCombatActionResolver();

export const registerLootDropHook = (hook: LootDropHook): (() => void) => {
  const previous = lootDropHook;
  lootDropHook = hook;

  return () => {
    if (lootDropHook === hook) {
      lootDropHook = previous;
    }
  };
};

export const registerAttackInterceptor = (
  interceptor: AttackInterceptor,
): (() => void) => {
  attackInterceptors.push(interceptor);

  return () => {
    const index = attackInterceptors.lastIndexOf(interceptor);

    if (index !== -1) {
      attackInterceptors.splice(index, 1);
    }
  };
};

const applyAttackInterceptors = (
  state: GameState,
  attackerId: CombatActorId,
  defenderId: CombatActorId,
): CombatActorId => {
  let nextDefenderId = defenderId;

  for (const interceptor of attackInterceptors) {
    nextDefenderId = interceptor(state, attackerId, nextDefenderId);
  }

