const throwImpact = (
  state: GameState,
  grid: TileGrid,
  origin: Position,
  targetCell: Position,
  range: number,
): ThrowImpact => {
  const cells: Position[] = [];

  for (const cell of line(origin, targetCell).slice(1, range + 1)) {
    if (!inBounds(grid, cell)) {
      break;
    }

    const tile = getTile(grid, cell);
    if (!isTransparentTile(tile)) {
      break;
    }

    cells.push(cell);

